SELECT SUM(CS.[DAILY_ARTICLES]) AS WEEKLY_ARTICLES,
	SUM(CS.[DAILY_VIEWS]) AS WEEKLY_VIEWS 
FROM [CATEGORY_STATISTICS] CS 
WHERE CS.[IsDeleted] = 0 
	AND CS.[CATEGORY_ID] = @PRM_CATEGORY_STATISTIC_CATEGORY_ID 
	AND CS.[STATISTICS_DATE] > DATEADD(DAY, -7,
	GETDATE()) 
